<?php require_once '../config/db.php'; require_once '../includes/auth.php'; require_admin(); $page_title='Members';
if(isset($_GET['delete'])){ $id=intval($_GET['delete']); mysqli_query($conn,"DELETE FROM PERSON WHERE person_id=$id"); header('Location: members.php'); exit(); }
if($_SERVER['REQUEST_METHOD']==='POST'){
    if($_POST['action']==='add'){
        mysqli_begin_transaction($conn); try{ $stmt=mysqli_prepare($conn,'INSERT INTO PERSON(first_name,last_name,date_of_birth,gender,street,city,email) VALUES(?,?,?,?,?,?,?)'); mysqli_stmt_bind_param($stmt,'sssssss',$_POST['first_name'],$_POST['last_name'],$_POST['date_of_birth'],$_POST['gender'],$_POST['street'],$_POST['city'],$_POST['email']); mysqli_stmt_execute($stmt); $pid=mysqli_insert_id($conn); $stmt=mysqli_prepare($conn,'INSERT INTO MEMBER(person_id,joining_date,health_goal,emergency_contact,member_status) VALUES(?,?,?,?,?)'); mysqli_stmt_bind_param($stmt,'issss',$pid,$_POST['joining_date'],$_POST['health_goal'],$_POST['emergency_contact'],$_POST['member_status']); mysqli_stmt_execute($stmt); $stmt=mysqli_prepare($conn,'INSERT INTO PERSON_PHONE(person_id,phone_number) VALUES(?,?)'); mysqli_stmt_bind_param($stmt,'is',$pid,$_POST['phone']); mysqli_stmt_execute($stmt); mysqli_commit($conn);}catch(Exception $e){mysqli_rollback($conn);} }
    if($_POST['action']==='edit'){ $id=intval($_POST['person_id']); $stmt=mysqli_prepare($conn,'UPDATE PERSON SET first_name=?,last_name=?,street=?,city=?,email=? WHERE person_id=?'); mysqli_stmt_bind_param($stmt,'sssssi',$_POST['first_name'],$_POST['last_name'],$_POST['street'],$_POST['city'],$_POST['email'],$id); mysqli_stmt_execute($stmt); $stmt=mysqli_prepare($conn,'UPDATE MEMBER SET health_goal=?, emergency_contact=?, member_status=? WHERE person_id=?'); mysqli_stmt_bind_param($stmt,'sssi',$_POST['health_goal'],$_POST['emergency_contact'],$_POST['member_status'],$id); mysqli_stmt_execute($stmt); }
    header('Location: members.php'); exit();
}
$edit=null; if(isset($_GET['edit'])){ $id=intval($_GET['edit']); $edit=mysqli_fetch_assoc(mysqli_query($conn,"SELECT p.*,m.* FROM PERSON p JOIN MEMBER m ON p.person_id=m.person_id WHERE p.person_id=$id")); }
$result=mysqli_query($conn,"SELECT m.person_id, CONCAT(p.first_name,' ',p.last_name) member_name, p.email, p.city, m.health_goal, m.joining_date, m.member_status FROM MEMBER m JOIN PERSON p ON m.person_id=p.person_id ORDER BY m.person_id DESC"); require_once '../includes/header.php'; require_once '../includes/sidebar.php'; ?>
<div class="card form-card"><h2><?= $edit?'Edit Member':'Add Member' ?></h2><form method="POST" class="form-grid"><input type="hidden" name="action" value="<?= $edit?'edit':'add' ?>"><input type="hidden" name="person_id" value="<?= safe($edit['person_id']??'') ?>"><div><label>First Name</label><input class="input" name="first_name" value="<?= safe($edit['first_name']??'') ?>" required></div><div><label>Last Name</label><input class="input" name="last_name" value="<?= safe($edit['last_name']??'') ?>" required></div><?php if(!$edit): ?><div><label>Date of Birth</label><input class="input" type="date" name="date_of_birth" required></div><div><label>Gender</label><select name="gender"><option>Male</option><option>Female</option><option>Other</option></select></div><?php endif; ?><div><label>Street</label><input class="input" name="street" value="<?= safe($edit['street']??'') ?>" required></div><div><label>City</label><input class="input" name="city" value="<?= safe($edit['city']??'') ?>" required></div><div><label>Email</label><input class="input" type="email" name="email" value="<?= safe($edit['email']??'') ?>" required></div><?php if(!$edit): ?><div><label>Phone</label><input class="input" name="phone" required></div><div><label>Joining Date</label><input class="input" type="date" name="joining_date" required></div><?php endif; ?><div><label>Health Goal</label><select name="health_goal"><?php foreach(['Weight Loss','Muscle Gain','Fitness','Strength Training','Endurance'] as $g): ?><option <?= ($edit['health_goal']??'')==$g?'selected':'' ?>><?= $g ?></option><?php endforeach; ?></select></div><div><label>Emergency Contact</label><input class="input" name="emergency_contact" value="<?= safe($edit['emergency_contact']??'') ?>" required></div><div><label>Status</label><select name="member_status"><?php foreach(['Active','Inactive','Suspended'] as $s): ?><option <?= ($edit['member_status']??'')==$s?'selected':'' ?>><?= $s ?></option><?php endforeach; ?></select></div><div class="full actions"><button class="btn"><?= $edit?'Update':'Add' ?> Member</button><?php if($edit): ?><a class="btn btn-light" href="members.php">Cancel</a><?php endif; ?></div></form></div><h2 class="section-title">Member Records</h2><div class="table-wrap"><table><tr><th>ID</th><th>Name</th><th>Email</th><th>City</th><th>Goal</th><th>Joining</th><th>Status</th><th>Actions</th></tr><?php while($r=mysqli_fetch_assoc($result)): ?><tr><td><?= safe($r['person_id']) ?></td><td><?= safe($r['member_name']) ?></td><td><?= safe($r['email']) ?></td><td><?= safe($r['city']) ?></td><td><?= safe($r['health_goal']) ?></td><td><?= safe($r['joining_date']) ?></td><td><span class="badge"><?= safe($r['member_status']) ?></span></td><td class="actions"><a class="btn btn-light" href="members.php?edit=<?= $r['person_id'] ?>">Edit</a><a class="btn btn-danger" onclick="return confirm('Delete member?')" href="members.php?delete=<?= $r['person_id'] ?>">Delete</a></td></tr><?php endwhile; ?></table></div><?php require_once '../includes/footer.php'; ?>
